/** A live cell's position as [x, y] coordinates. */
export type Cell = [number, number];

/**
 * Computes the next generation of Conway's Game of Life.
 * Returns the set of cells that will be alive in the next tick.
 */
export function nextGeneration(cells: Cell[]): Cell[] {
  const key = (x: number, y: number) => `${x},${y}`;
  const alive = new Set(cells.map(([x, y]) => key(x, y)));

  const neighborCounts = new Map<string, number>();
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const k = key(x + dx, y + dy);
        neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
      }
    }
  }

  const result: Cell[] = [];
  for (const [k, count] of neighborCounts) {
    const [xs, ys] = k.split(",");
    const x = Number(xs);
    const y = Number(ys);
    if (count === 3 || (count === 2 && alive.has(k))) {
      result.push([x, y]);
    }
  }
  return result;
}

